CREATE TABLE IF NOT EXISTS public.cbhpm_procedimentos (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  codigo text NOT NULL UNIQUE,
  descricao text NOT NULL,
  porte text,
  porte_anestesico text,
  grupo_id text,
  grupo_nome text,
  subgrupo_id text,
  subgrupo_nome text,
  created_at timestamptz NOT NULL DEFAULT now()
);

ALTER TABLE public.cbhpm_procedimentos ENABLE ROW LEVEL SECURITY;

DROP POLICY IF EXISTS cbhpm_select ON public.cbhpm_procedimentos;
CREATE POLICY cbhpm_select ON public.cbhpm_procedimentos
  FOR SELECT TO authenticated USING (true);

-- Add CBHPM reference columns to procedimentos
ALTER TABLE public.procedimentos ADD COLUMN IF NOT EXISTS codigo_cbhpm text;
